import{_ as l,c as i,o as e,ag as r}from"./chunks/framework.CuZitY5t.js";const u=JSON.parse('{"title":"日本 -> 廣島 -> 交通 -> 廣島交通指南","description":"","frontmatter":{},"headers":[],"relativePath":"日本/廣島/交通/交通.md","filePath":"docs/日本/廣島/交通/交通.md","lastUpdated":1742396662000}'),t={name:"日本/廣島/交通/交通.md"};function h(n,a,d,s,o,c){return e(),i("div",null,a[0]||(a[0]=[r('<h1 id="廣島交通指南" tabindex="-1">廣島交通指南 <a class="header-anchor" href="#廣島交通指南" aria-label="Permalink to “廣島交通指南”">​</a></h1><h2 id="抵達方式" tabindex="-1">抵達方式 <a class="header-anchor" href="#抵達方式" aria-label="Permalink to “抵達方式”">​</a></h2><h3 id="新幹線" tabindex="-1">新幹線 <a class="header-anchor" href="#新幹線" aria-label="Permalink to “新幹線”">​</a></h3><ul><li>從東京：約 4 小時</li><li>從大阪：約 1.5 小時</li><li>從博多：約 1 小時</li><li>建議購買 JR Pass 較為划算</li></ul><h3 id="飛機" tabindex="-1">飛機 <a class="header-anchor" href="#飛機" aria-label="Permalink to “飛機”">​</a></h3><p>廣島機場（HIJ）提供國內外航線：</p><ul><li>國內：東京、札幌、那霸等</li><li>國際：首爾、台北、香港等</li><li>機場巴士約 45 分鐘可抵達市區</li></ul><h2 id="市內交通" tabindex="-1">市內交通 <a class="header-anchor" href="#市內交通" aria-label="Permalink to “市內交通”">​</a></h2><h3 id="路面電車" tabindex="-1">路面電車 <a class="header-anchor" href="#路面電車" aria-label="Permalink to “路面電車”">​</a></h3><ul><li>覆蓋主要觀光景點</li><li>單程價格：180-280 日圓</li><li>一日券：700 日圓</li><li>運行時間：6:00-23:00</li></ul><h3 id="巴士" tabindex="-1">巴士 <a class="header-anchor" href="#巴士" aria-label="Permalink to “巴士”">​</a></h3><ul><li>廣島巴士</li><li>一日券：700 日圓</li><li>可使用 IC 卡（ICOCA、Suica 等）</li></ul><h3 id="觀光循環巴士" tabindex="-1">觀光循環巴士 <a class="header-anchor" href="#觀光循環巴士" aria-label="Permalink to “觀光循環巴士”">​</a></h3><ul><li>Meipuru-pu 觀光循環巴士</li><li>路線：和平公園、廣島城等主要景點</li><li>一日券：400 日圓</li><li>每 30-60 分鐘一班</li></ul><h2 id="交通-ic-卡" tabindex="-1">交通 IC 卡 <a class="header-anchor" href="#交通-ic-卡" aria-label="Permalink to “交通 IC 卡”">​</a></h2><p>推薦使用 ICOCA 卡：</p><ul><li>可搭乘 JR、電車、巴士</li><li>可在便利商店消費</li><li>可全額退還押金</li><li>與其他地區 IC 卡相互通用</li></ul>',17)]))}const b=l(t,[["render",h]]);e